import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    include: ['src/**/*.spec.ts'],
    globals: true,
    coverage: {
      provider: 'v8',
      reporter: ['json-summary', 'text'],
      include: ['src/**/*.ts'],
      exclude: ['src/**/*.spec.ts'],
    },
  },
});

import { describe, it, expect } from "vitest";
import { claimOffice } from "./claim-office.js";

describe("Claim Office", () => {
  // ─── Quote: Empty / Single Item Base Premiums ─────────────────────

  it.todo(
    "should return premium 5 G for an empty item list — only the processing fee"
  );

  it.todo(
    "should return premium 105 G for a single plain sword — 100 G base + 5 G fee"
  );

  it.todo(
    "should return premium 65 G for a single plain amulet — 60 G base + 5 G fee"
  );

  it.todo(
    "should return premium 85 G for a single plain staff — 80 G base + 5 G fee"
  );

  it.todo(
    "should return premium 45 G for a single plain potion — 40 G base + 5 G fee"
  );

  // ─── Quote: Component Base Premiums ───────────────────────────────

  it.todo(
    "should return premium 55 G for 2 runes — 50 G base (2 x 25 G) + 5 G fee"
  );

  it.todo(
    "should return premium 65 G for 3 runes — 60 G base (block of 3 alike) + 5 G fee"
  );

  it.todo(
    "should return premium 105 G for 4 runes — 100 G base (4 x 25 G, no block) + 5 G fee"
  );

  it.todo(
    "should return premium 180 G for 7 runes — 175 G base (7 x 25 G, no block) + 5 G fee"
  );

  // ─── Quote: "Alike" Components (different types) ──────────────────

  it.todo(
    "should return premium 80 G for 2 runes + 1 moonstone — 75 G base (no block: different types) + 5 G fee"
  );

  it.todo(
    "should return premium 125 G for 3 runes + 3 moonstones — 120 G base (two separate blocks) + 5 G fee"
  );

  // ─── Quote: Item-Level Modifiers ──────────────────────────────────

  it.todo(
    "should apply 50% cursed surcharge to the cursed item only — cursed sword (100 + 50 = 150 G) + 5 G fee = 155 G"
  );

  it.todo(
    "should apply 30% high-enchantment surcharge for enchantment >= 5 — sword enchantment 5: 100 + 30 = 130 G + 5 G fee = 135 G"
  );

  it.todo(
    "should not apply high-enchantment surcharge for enchantment 4 — sword enchantment 4: 100 G + 5 G fee = 105 G"
  );

  it.todo(
    "should apply both cursed and high-enchantment surcharges — cursed sword enchantment 5: 100 + 50 + 30 = 180 G + 5 G fee = 185 G"
  );

  // ─── Quote: Modifier Scope on Multi-Item Policies ─────────────────

  it.todo(
    "should apply cursed surcharge only to the cursed item in a multi-item policy — cursed sword (150 G) + plain amulet (60 G) = 210 G + 5 G fee = 215 G"
  );

  // ─── Quote: Policy-Level Modifiers ────────────────────────────────

  it.todo(
    "should apply 20% loyalty discount for customer with >= 2 years — sword: 100 G - 20 G loyalty + 5 G fee = 85 G"
  );

  it.todo(
    "should apply loyalty discount for customer with exactly 2 years — threshold is >= 2"
  );

  it.todo(
    "should apply 10% first insurance surcharge — every item in a quote is treated as first insurance"
  );

  it.todo(
    "should apply 15% follow-up contract discount on second quote — sword on second quote: 100 G - 15 G follow-up + 5 G fee = 90 G"
  );

  // ─── Quote: Integration — Newcomer with Cursed Sword ──────────────

  it.todo(
    "should return premium 165 G for newcomer (0 years, no previous contract) with cursed sword — 100 base + 50 curse + 10 first insurance = 160 + 5 fee"
  );

  // ─── Quote: Integration — Long-Standing Customer's Second Contract ─

  it.todo(
    "should return premium 160 G for long-standing customer (3 years, second quote) with cursed sword enchantment 7 — 100 base + 50 curse + 30 enchant - 20 loyalty + 10 first - 15 follow-up = 155 + 5 fee"
  );

  // ─── Quote: Rounding Premiums Up ──────────────────────────────────

  it.todo(
    "should round premium UP in MHPCO's favor — a calculation yielding 197.5 G results in 198 G"
  );

  // ─── Quote: Insurance Sum and Cap ─────────────────────────────────

  it.todo(
    "should compute insurance sum 2000 G and cap 4000 G for two swords"
  );

  it.todo(
    "should compute insurance sum 1600 G and cap 3200 G for a sword and an amulet"
  );

  it.todo(
    "should compute cap from unmodified insurance value — cursed sword: cap 2000 G (not affected by premium modifiers)"
  );

  it.todo(
    "should compute insurance sum 1750 G for a sword and 3 runes (block) — block discount affects premium only, not insurance sum"
  );

  // ─── Claim: Standard Reimbursement ────────────────────────────────

  it.todo(
    "should return payout 400 G for regular sword (steel, enchantment 3) with 500 G damage — full reimbursement minus 100 G deductible"
  );

  it.todo(
    "should return payout 100 G for rune with 200 G damage — full reimbursement minus 100 G deductible"
  );

  // ─── Claim: High-Enchantment Clause ───────────────────────────────

  it.todo(
    "should return payout 400 G for steel sword enchantment 9, damage 1000 G — 50% of 1000 = 500 minus 100 deductible"
  );

  // ─── Claim: Dragon Material Clause ────────────────────────────────

  it.todo(
    "should return payout 700 G for dragon-material sword enchantment 5, damage 800 G — dragon clause: full reimbursement 800 minus 100 deductible"
  );

  // ─── Claim: Both Clauses — 50% Rule Wins ──────────────────────────

  it.todo(
    "should return payout 400 G for dragon-material sword enchantment 9, damage 1000 G — both clauses: 50% wins (500 - 100)"
  );

  it.todo(
    "should return payout 400 G for dragon-material sword enchantment 8, damage 1000 G — enchantment >= 8 triggers 50% rule even with dragon material"
  );

  // ─── Claim: Deductible per Damaged Item ───────────────────────────

  it.todo(
    "should return payout 600 G when dragon attack damages sword (500 G) and amulet (300 G) — deductible applies once per damaged item: (500 - 100) + (300 - 100)"
  );

  // ─── Claim: Multiple Items of Same Type ───────────────────────────

  it.todo(
    "should handle two swords in policy — two sword damage entries each get separate deductible"
  );

  // ─── Claim: Cap Exhaustion ────────────────────────────────────────

  it.todo(
    "should return payout 1400 G on first claim of 1500 G for insured sword (cap 2000 G) — remaining cap 600 G"
  );

  it.todo(
    "should return payout 600 G on second claim of 1500 G after first claim used 1400 G — remaining cap 0 G"
  );

  // ─── Claim: Rounding Payouts Down ─────────────────────────────────

  it.todo(
    "should round payout DOWN in MHPCO's favor — a calculation yielding 350.5 G results in 350 G"
  );

  // ─── Edge Cases: Error Handling ───────────────────────────────────

  it.todo(
    "should exit non-zero for unknown item type in quote — e.g. type 'broomstick'"
  );

  it.todo(
    "should exit non-zero when claim references item not in policy — e.g. amulet damaged but only sword insured"
  );

  it.todo(
    "should exit non-zero for negative damage amount in claim — e.g. amount: -200"
  );

  it.todo(
    "should exit non-zero when damages array has more entries of a type than policy covers — e.g. two sword damages but only one sword insured"
  );
});

