const PROCESSING_FEE = 5;
const BLOCK_OF_THREE_PRICE = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function calculateItemPremium(item: any): number {
  const base = BASE_PREMIUMS[item.type];
  let premium = base;
  if (item.cursed) {
    premium += base * 0.5;
  }
  if (item.enchantment >= 5) {
    premium += base * 0.3;
  }
  return premium;
}

export function claimOffice(input: any): unknown {
  const items = input.steps[0].items;
  let itemsTotal = items.reduce(
    (sum: number, item: any) => sum + calculateItemPremium(item),
    0,
  );

  const typeCounts: Record<string, number> = {};
  for (const item of items) {
    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
  }
  for (const type in typeCounts) {
    if (typeCounts[type] === 3) {
      itemsTotal = itemsTotal - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
    }
  }

  if (input.customer.yearsWithMHPCO >= 2) {
    itemsTotal = itemsTotal * 0.8;
  }

  const premium = itemsTotal + PROCESSING_FEE;
  return { results: [{ premium }] };
}

