import { describe, it, expect } from "vitest";
import { claimOffice } from "./claim-office.js";

describe("Claim Office", () => {
  // ─── Quote: Empty / Single Item Base Premiums ─────────────────────

  it("should return premium 5 G for an empty item list — only the processing fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [],
        },
      ],
    };
    const result = claimOffice(input);
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  it("should return premium 105 G for a single plain sword — 100 G base + 5 G fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
          ],
        },
      ],
    };
    const result = claimOffice(input);
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });

  it("should return premium 65 G for a single plain amulet — 60 G base + 5 G fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    };
    const result = claimOffice(input);
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });

  it("should return premium 85 G for a single plain staff — 80 G base + 5 G fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "staff", material: "oak", enchantment: 0, cursed: false },
          ],
        },
      ],
    };
    const result = claimOffice(input);
    expect(result).toEqual({ results: [{ premium: 85 }] });
  });

  it("should return premium 45 G for a single plain potion — 40 G base + 5 G fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "potion", material: "glass", enchantment: 0, cursed: false },
          ],
        },
      ],
    };
    const result = claimOffice(input);
    expect(result).toEqual({ results: [{ premium: 45 }] });
  });

  // ─── Quote: Component Base Premiums ───────────────────────────────

  it("should return premium 55 G for 2 runes — 50 G base (2 x 25 G) + 5 G fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    };
    const result = claimOffice(input);
    expect(result).toEqual({ results: [{ premium: 55 }] });
  });

  it("should return premium 65 G for 3 runes — 60 G base (block of 3 alike) + 5 G fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    };
    const result = claimOffice(input);
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });

  it("should return premium 105 G for 4 runes — 100 G base (4 x 25 G, no block) + 5 G fee", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
