  // ─── Quote: Modifier Scope on Multi-Item Policies ─────────────────

  it("should apply cursed surcharge only to the cursed item in a multi-item policy — cursed sword (150 G) + plain amulet (60 G) = 210 G + 5 G fee = 215 G", () => {
    const input = {
